module RefModule(
    input clk,
    input reset,
    input up,
    output reg [2:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 3'b000;
    else if (up)
        q <= q + 1'b1;
    else
        q <= q - 1'b1;
end
endmodule
